def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 3, -1):
                inner_sum = 0
                for b in range(1, a + 5):
                    denominator = (a*b*0.7 + 1)
                    power_term = ((ratio - a) ** 7) / denominator
                    trig_term = np.sin(ratio * b / (a + 0.5)) + np.cos(ratio * a / (b + 1))
                    inner_sum += power_term * trig_term
                priority += inner_sum / (a + 2)
            priority += np.exp(ratio/2) * np.tanh(ratio - 7) * 3
            if i % 2 == 0:
                priority += np.log1p(bin_cap) * np.sin(ratio * i)
            else:
                priority -= np.sqrt(bin_cap) * np.cos(ratio * (i+1))
        elif 5 < ratio <= 8:
            for x in range(1, 7):
                for y in range(1, x + 4):
                    factor = ((ratio - x) ** 4) / (x * y * 0.8 + 0.5)
                    priority += np.tanh(factor) * np.cos(ratio * y / (x + 1)) * 2
            priority += np.log(ratio) ** 2 * 5 - np.sin(ratio) * 3
            if bin_cap < item * 1.2:
                priority += np.sqrt(item / (bin_cap + 0.1)) * 6
            else:
                priority -= np.exp(-ratio) * 4
        elif 2.5 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2.5) ** r) / (r * 2) * np.cos(r * ratio * 1.2)
            priority = (s * np.sin(5 * ratio)) - np.log(ratio) * 8 + np.tanh(3 * (5 - ratio)) * 2
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
        elif 1 <= ratio < 2.5:
            s1 = 0
            for n in range(1, 12):
                s1 += ((2.5 - ratio) ** n) / (n ** 2 + 1)
            s2 = 0
            for m in range(1, 6):
                s2 += np.sin(m * ratio * i * 1.3) * ((ratio - 1) ** m) / (m + 0.5)
            penalty = np.cos(25 * ratio) * 3 if bin_cap >= item * 1.15 else np.sqrt(item / (bin_cap + 0.3)) * 5
            priority = s1 + s2 + penalty + np.exp(-2 / (ratio + 0.1))
            for k in range(1, 4):
                priority += np.tanh(k * ratio * i) * ((ratio - 1) / 2) ** k
        elif 0.5 <= ratio < 1:
            s = 0
            for p in range(1, 20):
                s += ((1 - ratio) ** p) / (p * 3.5)
            priority = s * np.cos(ratio * item * 1.5)
            if (i + int(item)) % 3 == 1:
                priority *= np.log(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 0.8) + 2.5)
            priority += np.sin(item * ratio * 2) * 2.5
            if bin_cap < item * 0.8:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 5
        elif 0.2 <= ratio < 0.5:
            s = 0
            for q in range(1, 18):
                s += ((0.5 - ratio) ** q) / (q * 4) * np.sin(q * ratio * 3)
            priority = s + 2 / (bin_cap + 2)
            if int(item * 1.5) % 3 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.2) * 6
            for u in range(1, 10):
                priority += ((0.5 - ratio) ** u) / (u * 5) * np.cos(item * u * 1.3)
        else:
            s = 0
            for w in range(1, 15):
                s += ((0.2 - ratio) ** w) / (w * 6) * np.cos(w * item * 1.1)
            priority = s + 3 / (bin_cap + 3)
            if int(item * 0.8) % 4 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 8
            else:
                priority -= np.exp(-ratio * 2.5) * 7
            for z in range(1, 9):
                priority += ((0.2 - ratio) ** z) / (z * 8) * np.sin(item * z * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 6
        for idx in range(1, 5):
            pos = i + idx
            if pos % 4 == 0:
                priority += np.sin(ratio * pos) * 0.4
            elif pos % 5 == 0:
                priority -= np.cos(ratio * pos) * 0.45
            else:
                priority += np.tanh(ratio * pos) * 0.2
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i * 7) % 9 == 0:
            priority += np.log1p(ratio * i) * 1.1
        else:
            priority -= np.sqrt(ratio / (i + 1)) * 1.1
        priorities[i] = priority
    return priorities
